"use strict";(globalThis.webpackChunkdocusaurus_site=globalThis.webpackChunkdocusaurus_site||[]).push([[481],{21483(e,a,i){i.r(a),i.d(a,{assets:()=>l,contentTitle:()=>n,default:()=>u,frontMatter:()=>t,metadata:()=>s,toc:()=>c});const s=JSON.parse('{"id":"UserGuide/C06_Blob_analysis/S01_Blob_analysis_overview","title":"Blob analysis overview","description":"Blob analysis allows you to identify connected regions of pixels within an image, then calculate selected features of those regions. The regions are commonly known as blobs. Blobs are areas of touching pixels that are in the same logical pixel state. This pixel state is called the foreground state, while the alternate state is called the background state. Typically, the background has the value zero and the foreground is everything else (although some control is generally provided to reverse the sense).","source":"@site/docs/UserGuide/C06_Blob_analysis/S01_Blob_analysis_overview.md","sourceDirName":"UserGuide/C06_Blob_analysis","slug":"/UserGuide/C06_Blob_analysis/S01_Blob_analysis_overview","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C06_Blob_analysis/S01_Blob_analysis_overview","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"doctype":"UserGuide","part":"2D processing and analysis","chapter":"Blob_analysis","section":"Blob_analysis_overview","module_tag":"blob","product":"Aurora-Imaging-Library-user-guide","version":1100,"path":"UserGuide / 2D processing and analysis / blob / Blob analysis overview"},"sidebar":"userGuideSidebar","previous":{"title":"Blob analysis","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C06_Blob_analysis/ChapterInformation"},"next":{"title":"Steps to performing blob analysis","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C06_Blob_analysis/S02_Steps_to_performing_blob_analysis"}}');var o=i(74848),r=i(28453);const t={doctype:"UserGuide",part:"2D processing and analysis",chapter:"Blob_analysis",section:"Blob_analysis_overview",module_tag:"blob",product:"Aurora-Imaging-Library-user-guide",version:1100,path:"UserGuide / 2D processing and analysis / blob / Blob analysis overview"},n="Blob analysis overview",l={},c=[{value:"Aurora Imaging Library and blob analysis",id:"aurora-imaging-library-and-blob-analysis",level:2}];function d(e){const a={h1:"h1",h2:"h2",header:"header",li:"li",ol:"ol",p:"p",...(0,r.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(a.header,{children:(0,o.jsx)(a.h1,{id:"blob-analysis-overview",children:"Blob analysis overview"})}),"\n",(0,o.jsx)(a.p,{children:"Blob analysis allows you to identify connected regions of pixels within an image, then calculate selected features of those regions. The regions are commonly known as blobs. Blobs are areas of touching pixels that are in the same logical pixel state. This pixel state is called the foreground state, while the alternate state is called the background state. Typically, the background has the value zero and the foreground is everything else (although some control is generally provided to reverse the sense)."}),"\n",(0,o.jsx)(a.p,{children:"In many applications, we are interested only in blobs whose features satisfy certain criteria. Since computation is time-consuming, blob analysis is often performed as an elimination process whereby only blobs of interest are considered in further analysis. The steps involved in feature extraction are:"}),"\n",(0,o.jsxs)(a.ol,{children:["\n",(0,o.jsx)(a.li,{children:"Analyze an image and exclude or delete blobs that don't meet determined criteria."}),"\n",(0,o.jsx)(a.li,{children:"Analyze the remaining blobs to extract further features and determine their criteria."}),"\n"]}),"\n",(0,o.jsx)(a.p,{children:"Repeat these steps, as necessary, until you have all the blob measurement results you need."}),"\n",(0,o.jsx)(a.p,{children:"Reducing the raw data to just a few feature measurements generally produces more comprehensible and useful results."}),"\n",(0,o.jsx)(a.h2,{id:"aurora-imaging-library-and-blob-analysis",children:"Aurora Imaging Library and blob analysis"}),"\n",(0,o.jsx)(a.p,{children:"The Aurora Imaging Library package includes a Blob Analysis module that can extract a wide assortment of blob features, such as the blob area, perimeter, maximum diameter at a given angle (Feret diameter), minimum bounding box, and compactness."}),"\n",(0,o.jsx)(a.p,{children:"Aurora Imaging Library uses a user-specified blob identifier image to discriminate between blobs and the background. Controls are provided to allow you to specify how this identifier image is interpreted (which pixels are part of which blob). Blobs are considered to consist of either zero or non-zero pixels, depending on the foreground control setting. The non-zero pixels can either have any value or must be set to the maximum value of the buffer (for example, 0xff for an 8-bit image), depending on the identifier type (grayscale or binary). In addition, Aurora Imaging Library provides controls to take into account such blob image information as the pixel aspect ratio."}),"\n",(0,o.jsx)(a.p,{children:"For binary feature extractions, such as those that pertain to the overall shape of the blob, the blob identifier image is used for both identification and computation. For grayscale extractions (for example, the mean pixel value in a blob), you must also provide a grayscale image whose pixel values will be used in computation. Instead of providing a separate blob identifier image, you can provide a grayscale image buffer or 3D-processable depth map container with an ROI that acts as the blob identifier image."}),"\n",(0,o.jsx)(a.p,{children:"Aurora Imaging Library also allows you to combine computation results and merge them together into one result. It is also sometimes desirable to merge blobs with specific characteristics. Aurora Imaging Library supports this feature as well."}),"\n",(0,o.jsx)(a.p,{children:"The module provides some support for camera calibration. Although most results are calculated in pixels, if the blob identifier image has been associated with a camera calibration context, positional results can be returned in calibrated real-world units. If a grayscale image has also been provided, it must have the same camera calibration context for the results to be calibrated."}),"\n",(0,o.jsx)(a.p,{children:"With Aurora Imaging Library, you can perform blob analysis on 1-bit, 8-bit or 16-bit unsigned buffers."})]})}function u(e={}){const{wrapper:a}={...(0,r.R)(),...e.components};return a?(0,o.jsx)(a,{...e,children:(0,o.jsx)(d,{...e})}):d(e)}},28453(e,a,i){i.d(a,{R:()=>t,x:()=>n});var s=i(96540);const o={},r=s.createContext(o);function t(e){const a=s.useContext(r);return s.useMemo(function(){return"function"==typeof e?e(a):{...a,...e}},[a,e])}function n(e){let a;return a=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:t(e.components),s.createElement(r.Provider,{value:a},e.children)}}}]);